class Booking:
    def __init__(self, bookingid, flight, status):
        self.bookingid = bookingid
        self.passengers = []
        self.flight = flight
        self.status = status

    def add_passenger(self, name):
        self.passengers.append(name)

    def get_booking_details(self):
        print(f"Booking ID: {self.bookingid}")
        print(f"Flight: {self.flight}")
        print(f"Status: {self.status}")
        print("Passengers:")
        for passenger in self.passengers:
            print(passenger)

class GroupBooking(Booking):
    def __init__(self, bookingid, flight, status, group_size):
        super().__init__(bookingid, flight, status)
        self.group_size = group_size

    def add_group_member(self, name):
        if len(self.passengers) < self.group_size:
            self.passengers.append(name)
        else:
            print("Cannot add more passengers, group is full.")

    def view_group(self):
        print("Group members:")
        for passenger in self.passengers:
            print(passenger)

class CustomGroupBooking(GroupBooking):
    def __init__(self, bookingid, flight, status, group_size, group_name):
        super().__init__(bookingid, flight, status, group_size)
        self.group_name = group_name

    def get_group_details(self):
        print(f"Group Name: {self.group_name}")
        print(f"Booking ID: {self.bookingid}")
        print(f"Flight: {self.flight}")
        print(f"Status: {self.status}")
        print(f"Group Size: {self.group_size}")
        print("Passengers:")
        for passenger in self.passengers:
            print(passenger)

