def default_test():
    group_booking = GroupBooking("GB123", "FL456", "Confirmed", 5)
    group_booking.add_group_member("Alice")
    group_booking.add_group_member("Bob")
    group_booking.add_group_member("Charlie")
    group_booking.view_group()

    print("Group Size:", group_booking.group_size)
    custom_group_booking = CustomGroupBooking("CB123", "FL789", "Pending", 3, "Team Alpha")
    custom_group_booking.add_group_member("David")
    custom_group_booking.add_group_member("Eve")
    custom_group_booking.get_group_details()
